1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteStep {
6	  op: "quote";
7	  items: Array<Record<string, unknown>>;
8	}
9	
10	export interface ClaimStep {
11	  op: "claim";
12	  policy: number;
13	  incident: {
14	    cause: string;
15	    damages: Array<{ itemType: string; amount: number }>;
16	  };
17	}
18	
19	export type Step = QuoteStep | ClaimStep;
20	
21	export interface Scenario {
22	  customer: Customer;
23	  steps: Step[];
24	}
25	
26	export type StepResult =
27	  | { premium: number }
28	  | { payout: number; remainingCap: number };
29	
30	export interface ScenarioResult {
31	  results: StepResult[];
32	}
33	
34	const PROCESSING_FEE = 5;
35	
36	const BASE_PREMIUM: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	};
40	
41	const quotePremium = (step: QuoteStep): StepResult => {
42	  const itemBase = step.items.reduce(
43	    (sum, item) => sum + (BASE_PREMIUM[item.type as string] ?? 0),
44	    0,
45	  );
46	  const firstInsurance = itemBase * 0.1;
47	  return { premium: itemBase + firstInsurance + PROCESSING_FEE };
48	};
49	
50	const processStep = (step: Step): StepResult => {
51	  if (step.op === "quote") return quotePremium(step);
52	  return { payout: 0, remainingCap: 0 };
53	};
54	
55	export const runScenario = (scenario: Scenario): ScenarioResult => ({
56	  results: scenario.steps.map(processStep),
57	});
58

